    public async Task<TicketPurchaseResult> PurchaseTicketsAsync(TicketPurchaseRequest request)
    {
        if (request.Quantity <= 0)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero."
            };
        }

        int retryCount = 0;
        while (retryCount < MaxRetries)
        {
            try
            {
                using var transaction = await _context.Database.BeginTransactionAsync();
                
                var eventEntity = await _context.Events
                    .FromSqlRaw("SELECT * FROM Events WITH (UPDLOCK, ROWLOCK) WHERE Id = {0}", request.EventId)
                    .FirstOrDefaultAsync();

                if (eventEntity == null)
                {
                    await transaction.RollbackAsync();
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = "Event not found."
                    };
                }

                if (eventEntity.AvailableSeats < request.Quantity)
                {
                    await transaction.RollbackAsync();
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = $"Not enough seats available. Only {eventEntity.AvailableSeats} seats remaining."
                    };
                }

                eventEntity.AvailableSeats -= request.Quantity;

                var ticket = new Ticket
                {
                    EventId = request.EventId,
                    CustomerName = request.CustomerName,
                    CustomerEmail = request.CustomerEmail,
                    Quantity = request.Quantity,
                    TotalPrice = eventEntity.PricePerTicket * request.Quantity,
                    PurchaseDate = DateTime.UtcNow
                };

                _context.Tickets.Add(ticket);
                await _context.SaveChangesAsync();
                await transaction.CommitAsync();

                return new TicketPurchaseResult
                {
                    Success = true,
                    Message = "Tickets purchased successfully.",
                    Ticket = ticket
                };
            }
            catch (DbUpdateConcurrencyException)
            {
                retryCount++;
                if (retryCount >= MaxRetries)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = "Unable to complete purchase due to high concurrency. Please try again."
                    };
                }
                await Task.Delay(100 * retryCount);
            }
            catch (Exception ex)
            {
                return new TicketPurchaseResult
                {
                    Success = false,
                    Message = $"An error occurred: {ex.Message}"
                };
            }
        }

        return new TicketPurchaseResult
        {
            Success = false,
            Message = "Purchase failed after multiple retries."
        };
    }

